// import "./drawer.scss"
import { MDCDrawer } from "@material/drawer";
import { MDCList } from "@material/list";
import { consoleInfo, consoleError } from "../util/log";
import { setToggleMenuIconBtnOn, topAppBar } from "./topbar";
import { showAboutMeDialog } from "./dialog/AboutMeDialog";
import { showPreferenceDialog } from "./dialog/PreferenceDialog";
import { showSearchDialog } from "./dialog/SearchDialog";
import { getSectionTypeByPath, SECTION_TYPE_LENS, SECTION_TYPE_OPERA, SECTION_TYPE_POETRY, SECTION_TYPE_REPOST, SECTION_TYPE_TAGS } from "../base/constant";
import { isSafari, toggleElementClass } from "../util/tools";
import { setupIconButtonRipple } from "./button";
import { setupListItemRipple } from "./list";

const DRAWER_ITEM_ORIGINAL_ID = "drawer-a-original"
const DRAWER_ITEM_REPOST_ID = "drawer-a-repost"
const DRAWER_ITEM_POETRY_ID = "drawer-a-poetry"
const DRAWER_ITEM_OPERA_ID = "drawer-a-opera"
const DRAWER_ITEM_LENS_ID = "drawer-a-lens"
const DRAWER_ITEM_TAG_ID = "drawer-a-tag"
const DRAWER_ITEM_SEARCH_ID = "drawer-a-search"
const DRAWER_ITEM_PREFERENCE_ID = "drawer-a-preference"
const DRAWER_ITEM_ABOUT_ME_ID = "drawer-a-about-me"

let drawer: MDCDrawer | null = null
let drawerWrapperE: HTMLElement | null = null

export function initDrawer() {
    let drawerE = document.querySelector(".mdc-drawer")
    if (drawerE == null) {
        consoleError("Drawer not found")
        return
    }
    drawerWrapperE = drawerE.querySelector(".mdc-drawer__wrapper") as HTMLElement
    drawer = MDCDrawer.attachTo(drawerE)
    // 监听 menu 按钮点击
    topAppBar?.listen("MDCTopAppBar:nav", () => {
        toggleDrawer(!drawer!!.open)
    })
    // 监听 trigger 弹出 drawer
    const drawerTriggers = document.querySelectorAll(".drawer-trigger")
    for (const toggle of drawerTriggers) {
        let eventType = "click"
        if (!(toggle instanceof HTMLButtonElement) && isSafari())
            eventType = "pointerup"
        toggle.addEventListener(eventType, () => {
            toggleDrawer(!drawer?.open)
        })
    }
    // drawer 中的 icon-button
    const iconBtnShareE = document.querySelector("#drawer_btn_share")
    const iconBtnCloseE = document.querySelector("#drawer_btn_close")
    setupIconButtonRipple(iconBtnShareE as HTMLElement)
    setupIconButtonRipple(iconBtnCloseE as HTMLElement)
    iconBtnShareE?.addEventListener("click", () => {
        consoleInfo("Click drawer share button")
        import("./dialog/ShareDialog").then((component) => {
            component.showShareDialog()
            toggleDrawer(false)
        })
    })
    iconBtnCloseE?.addEventListener("click", () => {
        consoleInfo("Click drawer close button")
        toggleDrawer(false)
    })
    drawerE.querySelector(".drawer-header-text-container")?.addEventListener("dblclick", (event) => {
        import("./dialog/InfoDialog").then((component) => {
            component.showInfoDialog()
            toggleDrawer(false)
        })
    })

    // drawer 中的 list
    const listE = document.querySelector(".mdc-drawer .mdc-deprecated-list")
    if (listE == null) {
        consoleError("Drawer list not found")
        return
    }
    const liEList = listE.querySelectorAll("a.mdc-deprecated-list-item")
    const drawerList = MDCList.attachTo(listE)
    drawerList.singleSelection = true;
    const currentPageIndex = getCurrentPageIndex(liEList)
    const currentSelectedLiE = liEList[currentPageIndex] as HTMLElement
    drawerList.listElements.map(liE => setupListItemRipple(liE))
    // 初始化选中当前页面对应的板块 item
    drawerList.selectedIndex = currentPageIndex
    // TODO: 设置选中元素的 tabindex 为 -1，禁止列表获取焦点，可能触发 drawer 弹出时 chrome 自动滚动到焦点元素

    drawerE.addEventListener("MDCDrawer:opened", () => {
        // drawer 弹出时禁止 body 滚动
        toggleElementClass(document.body, "mdc-drawer-scroll-lock", true)
        // 关闭 toggle menu 图标切换，正常切换时，这里应该是 true
        setToggleMenuIconBtnOn(false)
        // 监听尺寸变化，保持 drawer 内容的偏移量正确
        // TODO: 支持手势关闭
    });
    drawerE.addEventListener("MDCDrawer:closed", () => {
        toggleElementClass(document.body, "mdc-drawer-scroll-lock", false)
        setToggleMenuIconBtnOn(false)
        // 恢复选中
        // drawerList.selectedIndex = currentPageIndex
    });

    consoleInfo("Drawer currentPageIndex " + currentPageIndex)
    listE.addEventListener("click", () => {
        // 恢复选中
        drawerList.selectedIndex = currentPageIndex
        currentSelectedLiE.focus()
        currentSelectedLiE.blur()
    });

    const searchE = listE.querySelector("#" + DRAWER_ITEM_SEARCH_ID)
    if (searchE == null) {
        consoleError("Drawer search item not found")
        return
    }
    const searchEHref = searchE.getAttribute("href")

    // iOS 端 safari 对 a 链接的 click 事件会有延迟，使用 pointerup 事件可避免这个问题
    const eventType = isSafari() ? "pointerup" : "click";

    searchE.addEventListener(eventType, () => {
        if (searchEHref == null || searchEHref == "") {
            consoleInfo("Click drawer list item " + DRAWER_ITEM_SEARCH_ID)
            showSearchDialog()
            toggleDrawer(false)
        }
    })

    listE.querySelector("#" + DRAWER_ITEM_PREFERENCE_ID)?.addEventListener(eventType, () => {
        consoleInfo("Click drawer list item " + DRAWER_ITEM_PREFERENCE_ID)
        showPreferenceDialog()
        toggleDrawer(false)
    })

    listE.querySelector("#" + DRAWER_ITEM_ABOUT_ME_ID)?.addEventListener(eventType, () => {
        consoleInfo("Click drawer list item " + DRAWER_ITEM_ABOUT_ME_ID)
        showAboutMeDialog()
        toggleDrawer(false)
    })
}

export function toggleDrawer(on: boolean) {
    if (drawer == null) return
    drawer.open = on
}

function getCurrentPageIndex(aEList: NodeListOf<Element>) {
    let section = getSectionTypeByPath(window.location.pathname)
    if (section.identifier == SECTION_TYPE_REPOST.identifier) {
        return findIndexById(aEList, DRAWER_ITEM_REPOST_ID)
    } else if (section.identifier == SECTION_TYPE_POETRY.identifier) {
        return findIndexById(aEList, DRAWER_ITEM_POETRY_ID)
    } else if (section.identifier == SECTION_TYPE_OPERA.identifier) {
        return findIndexById(aEList, DRAWER_ITEM_OPERA_ID)
    } else if (section.identifier == SECTION_TYPE_LENS.identifier) {
        return findIndexById(aEList, DRAWER_ITEM_LENS_ID)
    } else if (section.identifier == SECTION_TYPE_TAGS.identifier) {
        return findIndexById(aEList, DRAWER_ITEM_TAG_ID)
    } else {
        // 其余所有页面都显示随笔板块
        return findIndexById(aEList, DRAWER_ITEM_ORIGINAL_ID)
    }
}

function findIndexById(aEList: NodeListOf<Element>, id: string) {
    for (let i = 0; i < aEList.length; i++) {
        const aE = aEList[i]
        if (aE.getAttribute("id") == id) {
            return i
        }
    }
    return 0
}
