import { getLocalRepository } from "../../repository/LocalDb"
import { toggleElementClass } from "../../util/tools"
import { consoleError, consoleInfo } from "../../util/log"
import { getEventEmitter, type Events } from "../base/EventBus"

/**
 * 初始化主字体
 */
export function initFont() {
    // 废弃 handwritten 设置，TODO: 注意旧版本可能启用了这个设置项
    // const localHandWritingFontOn = localRepository.getHandWritingFontOn()
    // setHandwrittenFont(localHandWritingFontOn)
    checkNotoSerifSCFont()
    loadNecessaryFonts()
    getEventEmitter().on("fontChange", (data: Events["fontChange"]) => {
        consoleInfo("Font receive fontChange event, data = " + JSON.stringify(data))
        checkNotoSerifSCFont()
    })
    getEventEmitter().on("pageEvent", (data: Events["pageEvent"]) => {
        consoleInfo("Font receive pageEvent, event = " + data)
        if (data == "pageBackFromCache") {
            checkNotoSerifSCFont()
        }
    }) 
}

function checkNotoSerifSCFont() {
    const localNotoSerifSCFontOn = getLocalRepository().getNotoSerifSCFont()
    setNotoSerifSCFont(localNotoSerifSCFontOn)
}

export function setHandwrittenFont(on: boolean) {
    const bodyE = document.body
    toggleElementClass(bodyE, "font-handwritten", on)
}

export function setNotoSerifSCFont(on: boolean) {
    const bodyE = document.body
    toggleElementClass(bodyE, "font-noto-serif-sc", on)
    // toggleClassWithEnable(bodyE, "font-wenkai", on)
}

export function setNotoSansSCFont(on: boolean) {
    const bodyE = document.body
    toggleElementClass(bodyE, "font-noto-sans-sc", on)
}

/**
 * 按需加载其它字体
 */
function loadNecessaryFonts() {
    // 汉仪许静行楷
    const handwrittenIndexElements = document.querySelectorAll(".font-handwritten")
    if (handwrittenIndexElements.length > 0)
        import("./fontHandwritten").then().catch((e) => {
            consoleError("Load handwritten font error: " + e)
        })

    // 霞鹜文楷
    const wenKaiIndexElements = document.querySelectorAll(".font-wenkai")
    if (wenKaiIndexElements.length > 0)
        import("./fontWenKai").then().catch((e) => {
            consoleError("Load WenKai font error: " + e)
        })
}

// 动态加载云端字体
export function loadCloudFont(url: string, fontName: string): Promise<void> {
    // 检查是否已经加载过该字体
    if (document.querySelector(`link[href="${url}"]`)) {
        console.log(`Cloud font ${fontName} already loaded`);
        return Promise.resolve();
    }
    return new Promise((resolve, reject) => {
        const link = document.createElement("link");
        link.rel = "stylesheet";
        link.href = url;
        link.onload = () => {
            console.log(`Cloud font ${fontName} loaded successfully`);
            resolve();
        };
        link.onerror = () => {
            console.error(`Failed to load cloud font ${fontName}`);
            reject(new Error(`Failed to load cloud font: ${fontName}`));
        };
        document.head.appendChild(link);
    });
}