export function getPostDateByUrl(url: string): string {
    const regExp = new RegExp("(\\d{4})/(\\d{2})/(\\d{2})")
    const matches = url.match(regExp)
    if (matches != null) {
        return matches[1] + "年" + matches[2] + "月" + matches[3] + "日"
    }
    return ""
}

export function getSplittedDate(date: string): { year: string, month: string, day: string } {
    const regExp = new RegExp("(\\d{4})年(\\d{2})月(\\d{2})日")
    const matches = date.match(regExp)
    if (matches != null) {
        return { year: matches[1], month: matches[2], day: matches[3] }
    }
    return { year: "", month: "", day: "" }
}